config.script:
#include "50518"
function fopen() : fopen = false dim oOpenFormHLI : set oOpenFormHLI = page_.getopeninghliclone() dim oRedirectOpenFormHLI set oRedirectOpenFormHLI = asp_form_hli(oOpenFormHLI.prop(GVAR_PAGE_TEMPLATE),oOpenFormHLI,nothing) oRedirectOpenFormHLI.prop(GVAR_NEWTHREAD) = 1
dim oRedirectPage : set oRedirectPage = doc_.getpagehli(oRedirectOpenFormHLI) if not oRedirectPage is nothing then doc_.pushpage oRedirectPage end if end function
